// Build the Planner prompt.
// The Planner's only job: decide which tools to fetch based on the user's message.
const userMessage = ($input.first().json.message?.text || '').trim();

const prompt =
`You are a homelab monitoring planner. Choose the minimum tools needed to answer the user.

Available tools: ["cpu", "memory", "temperature", "disk"]

Rules:
- "cpu" and "memory" share one API call — include both if either is relevant
- "temperature" covers CPU, GPU, NVMe heat
- "disk" covers storage pools and free space
- For general health or unclear queries, include all tools
- Respond ONLY with valid compact JSON, no markdown, no explanation

Examples:
  User: why is proxmox slow   → {"tools":["cpu","memory","disk"]}
  User: is anything hot?      → {"tools":["temperature"]}
  User: check disk space      → {"tools":["disk"]}
  User: status                → {"tools":["cpu","memory","temperature","disk"]}

User message: "${userMessage}"
JSON:`;

return [{ json: { prompt, userMessage } }];

// Parse the LLM JSON output. Fall back to all tools if malformed.
const raw = ($input.first().json.response || '').trim();
const userMessage = $('Planner Prompt').first().json.userMessage;

let tools = ['cpu', 'memory', 'temperature', 'disk']; // safe default

try {
  // Strip potential markdown fences or leading text before {}
  const match = raw.match(/\{[\s\S]*?\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    if (Array.isArray(parsed.tools) && parsed.tools.length > 0) {
      tools = parsed.tools.map(t => t.toLowerCase().trim());
    }
  }
} catch (e) {
  // keep default
}

return [{
  json: {
    tools,
    userMessage,
    needsStatus: tools.includes('cpu') || tools.includes('memory'),
    needsTemp:   tools.includes('temperature'),
    needsDisk:   tools.includes('disk')
  }
}];

// Normalize raw API responses into compact structured JSON.
// items[0] = status or skip, items[1] = temp or skip, items[2] = disk or skip
const items = $input.all();

const statusItem = items[0]?.json;
const tempItem   = items[1]?.json;
const diskItem   = items[2]?.json;

const metrics = {};

// --- CPU & Memory (PVE Status) ---
if (!statusItem?.skipped && statusItem?.data) {
  const s = statusItem.data;
  metrics.cpu_percent  = parseFloat(((s.cpu || 0) * 100).toFixed(1));
  metrics.load_avg     = (s.loadavg || []).map(Number);
  metrics.uptime_days  = s.uptime ? parseFloat((s.uptime / 86400).toFixed(1)) : null;
  if (s.memory?.total) {
    metrics.memory_percent  = parseFloat(((s.memory.used / s.memory.total) * 100).toFixed(1));
    metrics.memory_used_gb  = parseFloat((s.memory.used  / 1073741824).toFixed(1));
    metrics.memory_total_gb = parseFloat((s.memory.total / 1073741824).toFixed(1));
  }
  if (s.rootfs?.total) {
    metrics.root_disk_percent = parseFloat(((s.rootfs.used / s.rootfs.total) * 100).toFixed(1));
  }
  if (s.swap?.total) {
    metrics.swap_percent = parseFloat(((s.swap.used / s.swap.total) * 100).toFixed(1));
  }
}

// --- Temperature ---
if (!tempItem?.skipped && tempItem?.data) {
  const t = tempItem.data;
  const cpuT  = t['k10temp-pci-00c3']?.Tctl?.temp1_input;
  const gpuT  = t['amdgpu-pci-0500']?.edge?.temp1_input;
  const nvmeT = t['nvme-pci-0400']?.Composite?.temp1_input;
  if (cpuT  != null) metrics.cpu_temp_c  = cpuT;
  if (gpuT  != null) metrics.gpu_temp_c  = gpuT;
  if (nvmeT != null) metrics.nvme_temp_c = nvmeT;
}

// --- Disk/Storage ---
if (!diskItem?.skipped && Array.isArray(diskItem?.data)) {
  metrics.storage = diskItem.data.map(d => ({
    name:         d.storage,
    type:         d.type,
    used_percent: parseFloat((d.used_fraction * 100).toFixed(1)),
    free_gb:      parseFloat((d.avail  / 1073741824).toFixed(1)),
    total_gb:     parseFloat((d.total  / 1073741824).toFixed(1))
  }));
}

const tools       = $('Parse Tool List').first().json.tools;
const userMessage = $('Parse Tool List').first().json.userMessage;

return [{ json: { metrics, tools, userMessage } }];

const { metrics, tools, userMessage } = $input.first().json;

// Pre-compute anomalies in JS — thresholds are NOT the LLM's job
const flags = [];
if (metrics.cpu_percent    >= 80) flags.push(`CPU at ${metrics.cpu_percent}% (high)`);
if (metrics.load_avg?.[0]  >= 8)  flags.push(`Load avg ${metrics.load_avg[0]} (very high — likely I/O wait or runaway process)`);
if (metrics.memory_percent >= 85) flags.push(`RAM at ${metrics.memory_percent}% (high — ${metrics.memory_used_gb}/${metrics.memory_total_gb} GB)`);
if (metrics.root_disk_percent >= 80) flags.push(`Root disk at ${metrics.root_disk_percent}%`);
if (metrics.cpu_temp_c     >= 85) flags.push(`CPU temp ${metrics.cpu_temp_c}°C (high — check fan/airflow)`);
if (metrics.nvme_temp_c    >= 70) flags.push(`NVMe ${metrics.nvme_temp_c}°C (warm)`);
(metrics.storage || []).forEach(s => {
  if (s.used_percent >= 80) flags.push(`Storage ${s.name}: ${s.used_percent}% used (${s.free_gb} GB free)`);
});

const flagsText = flags.length > 0
  ? flags.join('; ')
  : 'none — all metrics within normal range';

const metricsJson = JSON.stringify(metrics, null, 2);

// The Analyzer only writes the narrative — all numbers are pre-computed above
const prompt =
`You are a homelab monitoring AI. A user asked: "${userMessage}"

System metrics (only what was fetched):
${metricsJson}

Pre-flagged anomalies: ${flagsText}

Rules:
- If anomalies exist: explain the most likely root cause, suggest one concrete next step
- If all normal: one short sentence confirming it
- Do NOT repeat the numbers — they are shown above
- Avoid filler phrases like "based on the data" or "it appears"
- Under 60 words

Analysis:`;

return [{ json: { prompt, metrics, flags } }];

const llmRaw = ($input.first().json.response || '').trim();
const metrics = $('Normalize Metrics').first().json.metrics;
const flags   = $('Analyzer Prompt').first().json.flags;

// Strip echoed prompt prefix if LLM repeated it
const analysis = llmRaw
  .replace(/^analysis[:\s]*/i, '')
  .replace(/^note[:\s]*/i, '')
  .split('\n')
  .filter(l => l.trim())
  .slice(0, 6)
  .join('\n')
  .trim();

const hasIssues = flags.length > 0;
const icon      = hasIssues ? '⚠️' : '✅';
const headline  = hasIssues ? '*Issues detected*' : '*Systems nominal*';

// Compact metric header — only show what was actually fetched
const parts = [];
if (metrics.cpu_percent    != null) parts.push(`CPU: ${metrics.cpu_percent}%`);
if (metrics.memory_percent != null) parts.push(`RAM: ${metrics.memory_percent}%`);
if (metrics.cpu_temp_c     != null) parts.push(`Temp: ${metrics.cpu_temp_c}°C`);
if (metrics.uptime_days    != null) parts.push(`Up: ${metrics.uptime_days}d`);

const storageLines = (metrics.storage || [])
  .map(s => `  ${s.name}: ${s.used_percent}% (${s.free_gb} GB free)`)
  .join('\n');

let text = `${icon} ${headline}\n`;
if (parts.length)  text += `${parts.join(' | ')}\n`;
if (storageLines)  text += `Storage:\n${storageLines}\n`;
if (hasIssues) {
  text += `\n🔴 ${flags.join('\n🔴 ')}\n`;
}
text += `\n${analysis}`;

return [{ json: { text } }];
